module priority_mux_32bit(
  input [31:0] data_x,
  input [31:0] data_y,
  input [31:0] data_z,
  input sel_xy,
  output reg [31:0] mux_out
);

  always @(sel_xy) begin
    if (sel_xy)
      mux_out = data_x;
    else
      mux_out = data_y | data_z;
